const body = $json.body ?? $json;
const message = (body.smsBody ?? body.message ?? '').toString().trim();
if (!message) throw new Error("Field 'message' or 'smsBody' is required");
const sender = (body.sender ?? 'UNKNOWN').toString();
const preferredUiLanguage = (body.preferredUiLanguage ?? 'en').toString();
const preferredVoiceLanguage = (body.preferredVoiceLanguage ?? preferredUiLanguage).toString();
const phishingScore = Number(body.phishingScore ?? 0);
const modelLabel = (body.modelLabel ?? '').toString();
const messageLanguage = (body.messageLanguage ?? detectLanguage(message)).toString();
const links = Array.isArray(body.links) ? body.links : [...message.matchAll(/https?:\/\/[^\s]+/gi)].map(m => m[0]);
return [{ json: { sender, message, preferredUiLanguage, preferredVoiceLanguage, phishingScore, modelLabel, messageLanguage, links } }];
function detectLanguage(text) { if (/[\u0900-\u097F]/.test(text)) return 'hi'; if (/[\u0C80-\u0CFF]/.test(text)) return 'kn'; return 'en'; }

const input = $items('Normalize Input', 0, 0)[0].json;
const api = $json.result ?? {};
const phishingProb = Number(api.probabilities?.phishing ?? 0);
const confidencePercent = Math.round((Number(api.confidence ?? phishingProb) || 0) * 100);
const inheritedScore = Number(input.phishingScore ?? 0);
const finalScore = Math.max(confidencePercent, inheritedScore);
const isHighRisk = (api.label === 'phishing') || phishingProb >= 0.8 || finalScore >= 80;
const verdict = isHighRisk ? 'high_risk' : 'safe';
const urgency = /blocked|suspend|urgent|immediately|within \d+|verify now|kyc|pan|aadhaar|aadhar/i.test(input.message);
const hasLink = (input.links || []).length > 0;
const indicators = [];
if (api.label === 'phishing') indicators.push('Local fine-tuned model classified this message as phishing');
if (hasLink) indicators.push('Message contains one or more links');
if (urgency) indicators.push('Message uses urgency or identity-verification pressure');
if (input.modelLabel) indicators.push(`App-side label: ${input.modelLabel}`);
return [{ json: {
  verdict,
  finalScore,
  confidence: confidencePercent,
  familyAlertRecommended: verdict === 'high_risk',
  localized: {
    en: {
      explanation: verdict === 'high_risk' ? 'This message looks like a scam because it combines risky language, a clickable link, or urgency pressure.' : 'This message looks safe based on the current model result and message context.',
      action: verdict === 'high_risk' ? 'Do not click the link or reply. Call the official number from the real website or app.' : 'No strong phishing signs were found. Still avoid sharing OTP, PIN, or passwords.'
    },
    hi: {
      explanation: verdict === 'high_risk' ? 'यह संदेश धोखाधड़ी जैसा लग रहा है क्योंकि इसमें खतरनाक भाषा, लिंक या जल्दी कार्रवाई का दबाव है।' : 'मौजूदा मॉडल और संदेश संदर्भ के आधार पर यह संदेश सुरक्षित लगता है।',
      action: verdict === 'high_risk' ? 'लिंक मत खोलिए और जवाब मत दीजिए। आधिकारिक वेबसाइट या ऐप से सही नंबर लेकर खुद कॉल कीजिए।' : 'कोई मजबूत फ़िशिंग संकेत नहीं मिले। फिर भी OTP, PIN या पासवर्ड साझा मत कीजिए।'
    },
    kn: {
      explanation: verdict === 'high_risk' ? 'ಈ ಸಂದೇಶವು ಮೋಸದಂತಿದೆ, ಏಕೆಂದರೆ ಇದರಲ್ಲಿ ಅಪಾಯಕಾರಿ ಭಾಷೆ, ಲಿಂಕ್ ಅಥವಾ ತುರ್ತು ಒತ್ತಡ ಇದೆ.' : 'ಈಗಿನ ಮಾದರಿ ಮತ್ತು ಸಂದೇಶದ ಸಂದರ್ಭದ ಆಧಾರದ ಮೇಲೆ ಇದು ಸುರಕ್ಷಿತವಾಗಿರುವಂತೆ ಕಾಣುತ್ತದೆ.',
      action: verdict === 'high_risk' ? 'ಲಿಂಕ್ ತೆರೆಯಬೇಡಿ ಮತ್ತು ಉತ್ತರಿಸಬೇಡಿ. ಅಧಿಕೃತ ವೆಬ್‌ಸೈಟ್ ಅಥವಾ ಆಪ್‌ನ ಸರಿಯಾದ ಸಂಖ್ಯೆಗೆ ನೀವು ಸ್ವತಃ ಕರೆ ಮಾಡಿ.' : 'ಬಲವಾದ ಫಿಷಿಂಗ್ ಸೂಚನೆಗಳು ಕಂಡುಬಂದಿಲ್ಲ. ಆದರೂ OTP, PIN ಅಥವಾ ಪಾಸ್ವರ್ಡ್ ಹಂಚಿಕೊಳ್ಳಬೇಡಿ.'
    }
  },
  evidence: {
    sender: input.sender,
    messageLanguage: input.messageLanguage,
    originalPhishingScore: input.phishingScore,
    modelLabel: input.modelLabel,
    links: input.links,
    indicators
  }
}}];
